{
  "grammar": [
    {
      "pattern": "可以 + 給我/幫我 + object + 嗎？",
      "structure": ["可以", "給我/幫我", "object", "嗎"],
      "explanation_en": "Use 可以 to make polite requests, asking for an object or service.",
      "title": "Polite Requests with 可以",
      "meaning": "Asking for something politely",
      "when_to_use": [
        "When ordering at a café or shop",
        "When asking for an item like a menu, receipt, or utensil"
      ],
      "when_not_to_use": [
        "When offering something (use 要 or 想要)",
        "When asking for permission to do an action (use 可以 + verb)"
      ],
      "pragmatic_notes": "Common in Taiwan: '可以給我菜單嗎？' is natural and polite.",
      "word_order_notes": "Always start with 可以, then 給我/幫我, then the object, and end with 嗎.",
      "english_contrast": "English uses 'Can I have...?' or 'Could I get...?' Chinese uses 可以 similarly.",
      "korean_contrast": "Korean uses '~을 주세요' or '~을 주실 수 있나요?' The 可以 structure is equivalent to '~할 수 있나요?'",
      "negative_examples": [
        {
          "text": "給我可以咖啡嗎？",
          "error": "Word order is wrong: '給我' should come after '可以', not before."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我可以嗎？",
          "error": "This is incomplete; it means 'Can I?', but the object is missing. Specify what you want."
        }
      ],
      "transformation_drills": [
        "Change '我要一杯拿鐵' to a polite request using 可以."
      ],
      "production_drills": [
        "You are at a café. Ask for a glass of water politely."
      ],
      "common_error_patterns": [
        "Omitting the object",
        "Using 想要 instead of 可以"
      ],
      "repair_feedback": {
        "word_order": "Put 可以 first, then 給我/幫我, then the object, and 嗎 at the end.",
        "politeness": "Using 可以 softens the request; avoid direct commands like '給我' without 可以.",
        "vocabulary": "Use correct object nouns like 菜單, 水, 發票."
      }
    },
    {
      "pattern": "我想要 + object",
      "structure": ["我想要", "object"],
      "explanation_en": "Use 想要 to express a polite desire for an object, often used in ordering.",
      "title": "Expressing Wants with 想要",
      "meaning": "I would like...",
      "when_to_use": [
        "When ordering food/drinks at a café",
        "When stating what you want to buy in a shop"
      ],
      "when_not_to_use": [
        "When making a request for an action (use 可以)",
        "When you are very sure and want to be direct (use 要)"
      ],
      "pragmatic_notes": "想要 is softer than 要; it implies 'I would like' rather than 'I want'. Common in Taiwan.",
      "word_order_notes": "Subject + 想要 + object. No question word order; simply state what you want.",
      "english_contrast": "English 'I would like...' vs 'I want...' Similarly, 想要 is more polite than 要.",
      "korean_contrast": "Korean '원하다' is like 想要 but less common; use '주세요' for requests.",
      "negative_examples": [
        {
          "text": "我想要咖啡嗎？",
          "error": "Adding 嗎 is wrong; 想要 is a statement, not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我咖啡想要",
          "error": "Word order is incorrect; object should come after 想要."
        }
      ],
      "transformation_drills": [
        "Change '我要一杯紅茶' to a more polite statement using 想要."
      ],
      "production_drills": [
        "You want to order a small latte (小杯拿鐵). How do you say politely?"
      ],
      "common_error_patterns": [
        "Using 要 instead of 想要 for politeness",
        "Forgetting to include the object after 想要"
      ],
      "repair_feedback": {
        "word_order": "Subject + 想要 + object. Do not place the object before 想要.",
        "politeness": "Use 想要 instead of 要 to sound more polite.",
        "vocabulary": "Use appropriate object nouns like 拿鐵, 紅茶, or 豆漿."
      }
    },
    {
      "pattern": "不好意思/麻煩/請/幫我 + request",
      "structure": ["softener", "request"],
      "explanation_en": "Use politeness softeners to initiate requests politely.",
      "title": "Politeness Softeners",
      "meaning": "Adding polite expressions to requests",
      "when_to_use": [
        "When starting a request at a café or shop",
        "When asking for a favor or service"
      ],
      "when_not_to_use": [
        "When speaking to close friends (can use casual language)",
        "When the request is very urgent (still polite, but can be simplified)"
      ],
      "pragmatic_notes": "In Taiwan, starting with 不好意思 is very polite. 麻煩 is used when you are troubling someone. 請 is formal.",
      "word_order_notes": "The softener usually comes at the beginning of the sentence, immediately before the request (verb phrase or object).",
      "english_contrast": "English uses 'Excuse me,' 'Please,' or 'Could you please...' Similarly, Chinese uses these starters.",
      "korean_contrast": "Korean uses '실례합니다' (excuse me) or '부탁합니다' (please). Similar function.",
      "negative_examples": [
        {
          "text": "不好意思，嗎？",
          "error": "The request is missing; after the softener, you need to state what you want."
        }
      ],
      "incorrect_examples": [
        {
          "text": "請嗎給我菜單？",
          "error": "After 請, do not use 嗎; the request is a statement. It should be '請給我菜單'."
        }
      ],
      "transformation_drills": [
        "Add a politeness softener to '給我菜單'."
      ],
      "production_drills": [
        "You want to ask for a bag (袋子) politely at a shop. Use a softener."
      ],
      "common_error_patterns": [
        "Using multiple softeners redundantly (e.g., '不好意思，麻煩請...')",
        "Using 嗎 after 請"
      ],
      "repair_feedback": {
        "word_order": "Place the softener at the start, then the request (e.g., verb + object).",
        "politeness": "Using a softener makes the request more polite; avoid starting directly with the request.",
        "vocabulary": "Choose the appropriate softener: 不好意思 for polite attention, 麻煩 for when troubling someone, 請 for formal requests."
      }
    }
  ]
}
